import os
import json
import argparse
import heapq
import traceback
import glob
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def pick_action(obs, last_target_coord):
    try:
        neighbors = obs['neighbors']
        nodes = obs['nodes']
        explored_rate = obs.get('explored_rate', 0.0)
    except Exception:
        return None, last_target_coord
    if not neighbors or not nodes:
        return None, last_target_coord
    try:
        robot = np.array(obs['robot_pos'], dtype=float)
        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            return neighbors[0], last_target_coord
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        late_phase = explored_rate >= 0.7

        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            if late_phase:
                score = np.sqrt(u) / (d + 1.0)
            else:
                score = u / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        if scored:
            target_idx = scored[0][1]
            if last_target_coord is not None:
                for sc, idx, u, d in scored[:5]:
                    if np.linalg.norm(coords[idx] - last_target_coord) < 0.5:
                        if sc >= scored[0][0] * 0.75:
                            target_idx = idx
                        break
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            new_last = coords[target_idx].copy()
            return chosen, new_last
        else:
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
                return chosen, None
            return neighbors[0], None
    except Exception:
        traceback.print_exc()
        try:
            return neighbors[0], last_target_coord
        except Exception:
            return None, last_target_coord


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()
    last_target_coord = None
    for step in range(max_steps):
        chosen, last_target_coord = pick_action(obs, last_target_coord)
        if chosen is None:
            break
        try:
            obs, info = env.step(chosen)
        except Exception:
            traceback.print_exc()
            break
        if info.get('done', False):
            break
    metrics = env.get_metrics()
    return metrics


def infer_env_type(rel_path):
    parts = rel_path.replace('\\', '/').split('/')
    for p in parts:
        if p in ('room', 'tunnel', 'outdoor'):
            return p
    return 'unknown'


def collect_episodes(data_path):
    """Return list of dicts with keys: map_abs, map_rel, env_type."""
    episodes = []
    cfg_path = os.path.join(data_path, 'eval_config.json')
    maps_root_candidates = [
        os.path.join(data_path, 'maps_eval'),
        data_path,
    ]

    cfg = None
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path, 'r') as f:
                cfg = json.load(f)
        except Exception:
            cfg = None

    # Try parsing eval_config
    map_entries = []
    if cfg is not None:
        if isinstance(cfg, list):
            map_entries = cfg
        elif isinstance(cfg, dict):
            for key in ('episodes', 'maps', 'eval', 'evaluation'):
                if key in cfg and isinstance(cfg[key], list):
                    map_entries = cfg[key]
                    break

    parsed = []
    for ent in map_entries:
        if isinstance(ent, str):
            map_rel = ent
            env_type = infer_env_type(map_rel)
        elif isinstance(ent, dict):
            map_rel = ent.get('map_path') or ent.get('path') or ent.get('map') or ent.get('file')
            env_type = ent.get('env_type') or infer_env_type(map_rel or '')
        else:
            continue
        if not map_rel:
            continue
        # resolve absolute path
        candidates = []
        for root in maps_root_candidates:
            candidates.append(os.path.join(root, map_rel))
        candidates.append(map_rel)  # absolute or relative
        abs_path = None
        for c in candidates:
            if os.path.exists(c):
                abs_path = c
                break
        if abs_path is None:
            # try basename match
            bn = os.path.basename(map_rel)
            for root in maps_root_candidates:
                matches = glob.glob(os.path.join(root, '**', bn), recursive=True)
                if matches:
                    abs_path = matches[0]
                    break
        if abs_path is not None:
            parsed.append({'map_abs': abs_path, 'map_rel': map_rel, 'env_type': env_type})

    if parsed:
        return parsed

    # Fallback: scan maps_eval/ directory
    for root in maps_root_candidates:
        if not os.path.isdir(root):
            continue
        # find all png files
        for png in sorted(glob.glob(os.path.join(root, '**', '*.png'), recursive=True)):
            rel = os.path.relpath(png, root)
            env_type = infer_env_type(rel)
            parsed.append({'map_abs': png, 'map_rel': rel, 'env_type': env_type})
        if parsed:
            break

    return parsed


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, default='')
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    try:
        episodes_to_run = collect_episodes(args.data_path)
    except Exception:
        traceback.print_exc()
        episodes_to_run = []

    print(f'Found {len(episodes_to_run)} episodes to run', flush=True)

    per_episode = []
    for i, ep in enumerate(episodes_to_run):
        try:
            metrics = plan_episode(ep['map_abs'], max_steps=128)
            er = float(metrics.get('explored_rate', 0.0))
            td = float(metrics.get('travel_distance', 0.0))
            success = 1 if er > 0.9999 else 0
            per_episode.append({
                'map_path': ep['map_rel'],
                'env_type': ep['env_type'],
                'success': success,
                'travel_distance': td,
                'explored_rate': er,
            })
            if i % 10 == 0:
                print(f'  [{i+1}/{len(episodes_to_run)}] {ep["map_rel"]}: er={er:.3f} td={td:.1f} s={success}', flush=True)
        except Exception:
            traceback.print_exc()
            per_episode.append({
                'map_path': ep['map_rel'],
                'env_type': ep['env_type'],
                'success': 0,
                'travel_distance': 0.0,
                'explored_rate': 0.0,
            })

    # Aggregate
    if per_episode:
        explored_mean = float(np.mean([e['explored_rate'] for e in per_episode]))
        succ = [e for e in per_episode if e['success'] == 1]
        travel_mean = float(np.mean([e['travel_distance'] for e in succ])) if succ else 0.0
        success_rate = float(np.mean([e['success'] for e in per_episode]))
    else:
        explored_mean = 0.0
        travel_mean = 0.0
        success_rate = 0.0

    pt_summary = {}
    types = set(e['env_type'] for e in per_episode)
    for t in types:
        eps = [e for e in per_episode if e['env_type'] == t]
        if not eps:
            continue
        em = float(np.mean([e['explored_rate'] for e in eps]))
        succ = [e for e in eps if e['success'] == 1]
        tm = float(np.mean([e['travel_distance'] for e in succ])) if succ else 0.0
        sr = float(np.mean([e['success'] for e in eps]))
        pt_summary[t] = {'explored_rate': em, 'travel_distance': tm, 'success_rate': sr}

    out = {
        'explored_rate': explored_mean,
        'travel_distance': travel_mean,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': pt_summary,
        'total_episodes': len(per_episode),
    }

    os.makedirs(os.path.dirname(os.path.abspath(args.output)) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(out, f, indent=2)
    print(f'Wrote {args.output} with {len(per_episode)} episodes', flush=True)


if __name__ == '__main__':
    try:
        main()
    except Exception:
        traceback.print_exc()
        # ensure output file exists
        try:
            parser = argparse.ArgumentParser()
            parser.add_argument('--data_path', type=str, required=True)
            parser.add_argument('--checkpoint', type=str, default='')
            parser.add_argument('--output', type=str, required=True)
            args, _ = parser.parse_known_args()
            with open(args.output, 'w') as f:
                json.dump({
                    'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0,
                    'per_episode': [], 'per_type': {}, 'total_episodes': 0,
                }, f)
        except Exception:
            pass
